     1→/**
     2→ * MMS Infinite Canvas
     3→ *
     4→ * The main canvas component that renders PM schedule data at different zoom levels.
     5→ * Uses deck.gl for strategic view (WebGL) and Konva for tactical/operational views (Canvas 2D).
     6→ *
     7→ * Zoom Level Rendering:
     8→ * - STRATEGIC (0-4): deck.gl WebGL heatmap
     9→ * - TACTICAL_WIDE (4-8): deck.gl WebGL compressed blocks
    10→ * - TACTICAL (8-12): Konva HTML5 Canvas Gantt
    11→ * - OPERATIONAL (12-16): Konva HTML5 Canvas detailed cards
    12→ * - DETAIL (16+): React DOM overlay
    13→ *
    14→ * Based on specs/006-user-interface.md Section 6.3.
    15→ */
    16→
    17→import { useRef } from 'react';
    18→import { Card, NonIdealState, Spinner, Tag, Button, ButtonGroup } from '@blueprintjs/core';
    19→
    20→import { useCanvas, useCanvasData, useFleet, loadStrategicData, loadTacticalData, loadTacticalWideData } from '../../store';
    21→import type { CanvasSliceState } from '../../store/slices/canvas';
    22→import type { CanvasDataState } from '../../store/slices/canvas';
    23→import type { FleetSliceState } from '../../store/slices/fleet';
    24→import { StrategicHeatmapLayer, TacticalWideLayer, TacticalGanttLayer, type HeatmapCell, type PmBlock } from './layers';
    25→
    26→/** Default canvas dimensions when container size is not available */
    27→const DEFAULT_CANVAS_WIDTH = 1200;
    28→const DEFAULT_CANVAS_HEIGHT = 800;
    29→
    30→export function InfiniteCanvas() {
    31→  const { state: canvasStateRaw, actions: canvasActions } = useCanvas();
    32→  const { state: canvasDataStateRaw, actions: canvasDataActions } = useCanvasData();
    33→  const { state: fleetStateRaw } = useFleet();
    34→
    35→  const canvasState = canvasStateRaw as unknown as CanvasSliceState;
    36→  const canvasDataState = canvasDataStateRaw as unknown as CanvasDataState;
    37→  const fleetState = fleetStateRaw as unknown as FleetSliceState;
    38→
    39→  const { zoom, zoomLevel, viewport, isPanning, layers } = canvasState;
    40→  const {
    41→    strategicData, strategicLoading, strategicError, fromYear, toYear,
    42→    tacticalWideData, tacticalWideLoading, tacticalWideError, tacticalWideFromDate, tacticalWideToDate,
    43→    tacticalData, tacticalLoading, tacticalError, tacticalFromDate, tacticalToDate
    44→  } = canvasDataState;
    45→  const isLoading = fleetState.trains.length === 0;
    46→
    47→  const tooltipPosRef = useRef<{ x: number; y: number }>({ x: 0, y: 0 });
    48→  const tooltipRef = useRef<HTMLDivElement>(null);
    49→
    50→  const handleWheel = (event: React.WheelEvent) => {
    51→    event.preventDefault();
    52→    const delta = event.deltaY > 0 ? -0.5 : 0.5;
    53→    const newZoom = Math.max(0, Math.min(20, zoom + delta));
    54→    canvasActions.setZoom(newZoom);
    55→  };
    56→
    57→  const handleMouseDown = (event: React.MouseEvent) => {
    58→    if (event.button === 0) {
    59→      canvasActions.startPanning();
    60→    }
    61→  };
    62→
    63→  const handleMouseUp = () => {
    64→    canvasActions.stopPanning();
    65→  };
    66→
    67→  const handleMouseMove = (event: React.MouseEvent) => {
    68→    if (isPanning) {
    69→      canvasActions.pan({
    70→        dx: -event.movementX,
    71→        dy: -event.movementY,
    72→      });
    73→    }
    74→    tooltipPosRef.current = { x: event.clientX, y: event.clientY };
    75→  };
    76→
    77→  const handleLoadStrategicData = () => {
    78→    loadStrategicData(canvasDataActions, {
    79→      fromYear,
    80→      toYear,
    81→    });
    82→  };
    83→
    84→  const handleLoadTacticalWideData = () => {
    85→    loadTacticalWideData(canvasDataActions, {
    86→      fromDate: tacticalWideFromDate,
    87→      toDate: tacticalWideToDate,
    88→    });
    89→  };
    90→
    91→  const handleLoadTacticalData = () => {
    92→    loadTacticalData(canvasDataActions, {
    93→      fromWeek: tacticalFromDate,
    94→      toWeek: tacticalToDate,
    95→    });
    96→  };
    97→
    98→  const handlePmBlockHover = (pm: PmBlock | null) => {
    99→    if (tooltipRef.current) {
   100→      if (pm) {
   101→        tooltipRef.current.style.display = 'block';
   102→        tooltipRef.current.style.left = `${tooltipPosRef.current.x + 10}px`;
   103→        tooltipRef.current.style.top = `${tooltipPosRef.current.y + 10}px`;
   104→        tooltipRef.current.innerHTML = `
   105→          <div style="font-weight: 600; margin-bottom: 4px;">
   106→            ${pm.pmCode} - ${pm.trainNumber}
   107→          </div>
   108→          <div style="color: #64748b;">
   109→            <div>Date: <strong>${pm.targetDate}</strong></div>
   110→            <div>Duration: <strong>${pm.durationDays} day${pm.durationDays > 1 ? 's' : ''}</strong></div>
   111→            <div>Status: <strong>${pm.status}</strong></div>
   112→            ${pm.depotCode ? `<div>Depot: <strong>${pm.depotCode}</strong></div>` : ''}
   113→            ${pm.trackNumber ? `<div>Track: <strong>${pm.trackNumber}</strong></div>` : ''}
   114→            ${pm.estimatedHours ? `<div>Hours: <strong>${pm.estimatedHours}h</strong></div>` : ''}
   115→            ${pm.isLocked ? '<div style="color: #d97706;">🔒 Locked</div>' : ''}
   116→          </div>
   117→        `;
   118→      } else {
   119→        tooltipRef.current.style.display = 'none';
   120→      }
   121→    }
   122→  };
   123→
   124→  const handlePmBlockClick = (pmId: string) => {
   125→    canvasActions.selectPm(pmId);
   126→  };
   127→
   128→  // Tactical-Wide block handlers
   129→  const handleTacticalWideBlockHover = (block: { pmId: string; trainNumber: string; pmCode: string; targetDate: string; status: string; durationWeeks: number; isLocked: boolean } | null) => {
   130→    if (tooltipRef.current) {
   131→      if (block) {
   132→        tooltipRef.current.style.display = 'block';
   133→        tooltipRef.current.style.left = `${tooltipPosRef.current.x + 10}px`;
   134→        tooltipRef.current.style.top = `${tooltipPosRef.current.y + 10}px`;
   135→        tooltipRef.current.innerHTML = `
   136→          <div style="font-weight: 600; margin-bottom: 4px;">
   137→            ${block.pmCode} - ${block.trainNumber}
   138→          </div>
   139→          <div style="color: #64748b;">
   140→            <div>Date: <strong>${block.targetDate}</strong></div>
   141→            <div>Status: <strong>${block.status}</strong></div>
   142→            <div>Duration: <strong>~${block.durationWeeks} week(s)</strong></div>
   143→            ${block.isLocked ? '<div style="color: #d97706;">🔒 Locked</div>' : ''}
   144→          </div>
   145→        `;
   146→      } else {
   147→        tooltipRef.current.style.display = 'none';
   148→      }
   149→    }
   150→  };
   151→
   152→  const handleTacticalWideBlockClick = (block: { pmId: string }) => {
   153→    canvasActions.selectPm(block.pmId);
   154→  };
   155→
   156→  const handleMonthClick = (month: number, year: number) => {
   157→    // Zoom into tactical view for the clicked month
   158→    canvasActions.setZoom(10); // Move to TACTICAL zoom level
   159→    const startDate = new Date(year, month, 1);
   160→    const endDate = new Date(year, month + 3, 0); // 3 months view
   161→    canvasActions.setViewport({
   162→      startDate: startDate.toISOString().split('T')[0],
   163→      endDate: endDate.toISOString().split('T')[0],
   164→    });
   165→  };
   166→
   167→  const handleCellHover = (cell: HeatmapCell | null) => {
   168→    if (tooltipRef.current) {
   169→      if (cell) {
   170→        tooltipRef.current.style.display = 'block';
   171→        tooltipRef.current.style.left = `${tooltipPosRef.current.x + 10}px`;
   172→        tooltipRef.current.style.top = `${tooltipPosRef.current.y + 10}px`;
   173→        tooltipRef.current.innerHTML = `
   174→          <div style="font-weight: 600; margin-bottom: 4px;">
   175→            Train ${cell.trainNumber} - ${cell.year}
   176→          </div>
   177→          <div style="color: #64748b;">
   178→            <div>PM Count: <strong>${cell.pmCount}</strong></div>
   179→            <div>Total Hours: <strong>${cell.totalHours.toFixed(1)}h</strong></div>
   180→            ${cell.completedCount > 0 ? `<div>Completed: <strong>${cell.completedCount}</strong></div>` : ''}
   181→            ${cell.lockedCount > 0 ? `<div>Locked: <strong>${cell.lockedCount}</strong></div>` : ''}
   182→          </div>
   183→        `;
   184→      } else {
   185→        tooltipRef.current.style.display = 'none';
   186→      }
   187→    }
   188→  };
   189→
   190→  const handleCellClick = (cell: HeatmapCell) => {
   191→    canvasActions.setZoom(6);
   192→    canvasActions.setViewport({
   193→      startDate: `${cell.year}-01-01`,
   194→      endDate: `${cell.year}-12-31`,
   195→      trainIds: [cell.trainId],
   196→    });
   197→  };
   198→
   199→  const handleYearClick = (year: number) => {
   200→    canvasActions.setZoom(6);
   201→    canvasActions.setViewport({
   202→      startDate: `${year}-01-01`,
   203→      endDate: `${year}-12-31`,
   204→    });
   205→  };
   206→
   207→  const renderContent = () => {
   208→    if (isLoading) {
   209→      return (
   210→        <NonIdealState
   211→          icon={<Spinner size={48} />}
   212→          title="Loading fleet data..."
   213→          description="Fetching trains and PM schedule"
   214→        />
   215→      );
   216→    }
   217→
   218→    if (fleetState.trains.length === 0) {
   219→      return (
   220→        <NonIdealState
   221→          icon="train"
   222→          title="No trains found"
   223→          description="No trains match the current filters"
   224→        />
   225→      );
   226→    }
   227→
   228→    if (zoomLevel === 'STRATEGIC') {
   229→      if (strategicLoading) {
   230→        return (
   231→          <NonIdealState
   232→            icon={<Spinner size={48} />}
   233→            title="Loading strategic view..."
   234→            description="Fetching PM density data"
   235→          />
   236→        );
   237→      }
   238→
   239→      if (strategicError) {
   240→        return (
   241→          <NonIdealState
   242→            icon="error"
   243→            title="Error loading strategic view"
   244→            description={strategicError}
   245→            action={
   246→              <Button intent="primary" onClick={handleLoadStrategicData}>
   247→                Retry
   248→              </Button>
   249→            }
   250→          />
   251→        );
   252→      }
   253→
   254→      if (!strategicData) {
   255→        return (
   256→          <NonIdealState
   257→            icon="heat-grid"
   258→            title="Strategic View"
   259→            description="Load PM density heatmap for multi-year planning"
   260→            action={
   261→              <ButtonGroup>
   262→                <Button intent="primary" onClick={handleLoadStrategicData}>
   263→                  Load Strategic Data
   264→                </Button>
   265→              </ButtonGroup>
   266→            }
   267→          >
   268→            <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
   269→              <p>Shows 10-year PM density across {fleetState.trains.length} trains</p>
   270→            </div>
   271→          </NonIdealState>
   272→        );
   273→      }
   274→
   275→      return (
   276→        <>
   277→          <StrategicHeatmapLayer
   278→            data={strategicData}
   279→            fromYear={fromYear}
   280→            toYear={toYear}
   281→            width="100%"
   282→            height="100%"
   283→            onCellHover={handleCellHover}
   284→            onCellClick={handleCellClick}
   285→            onYearClick={handleYearClick}
   286→          />
   287→          <div
   288→            ref={tooltipRef}
   289→            style={{
   290→              display: 'none',
   291→              position: 'fixed',
   292→              backgroundColor: 'white',
   293→              border: '1px solid #e2e8f0',
   294→              borderRadius: '6px',
   295→              padding: '8px 12px',
   296→              boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
   297→              pointerEvents: 'none',
   298→              zIndex: 100,
   299→              fontSize: '12px',
   300→              lineHeight: 1.5,
   301→            }}
   302→          />
   303→        </>
   304→      );
   305→    }
   306→
   307→    if (zoomLevel === 'TACTICAL_WIDE') {
   308→      if (tacticalWideLoading) {
   309→        return (
   310→          <NonIdealState
   311→            icon={<Spinner size={48} />}
   312→            title="Loading tactical-wide view..."
   313→            description="Fetching yearly PM schedule data"
   314→          />
   315→        );
   316→      }
   317→
   318→      if (tacticalWideError) {
   319→        return (
   320→          <NonIdealState
   321→            icon="error"
   322→            title="Error loading tactical-wide view"
   323→            description={tacticalWideError}
   324→            action={
   325→              <Button intent="primary" onClick={handleLoadTacticalWideData}>
   326→                Retry
   327→              </Button>
   328→            }
   329→          />
   330→        );
   331→      }
   332→
   333→      if (!tacticalWideData) {
   334→        return (
   335→          <NonIdealState
   336→            icon="calendar"
   337→            title="Tactical Wide View"
   338→            description="Load 1-year PM schedule with monthly granularity"
   339→            action={
   340→              <ButtonGroup>
   341→                <Button intent="primary" onClick={handleLoadTacticalWideData}>
   342→                  Load Tactical Wide Data
   343→                </Button>
   344→              </ButtonGroup>
   345→            }
   346→          >
   347→            <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
   348→              <p>Shows PM schedule from {tacticalWideFromDate} to {tacticalWideToDate}</p>
   349→              <p>Monthly granularity with compressed Gantt blocks</p>
   350→            </div>
   351→          </NonIdealState>
   352→        );
   353→      }
   354→
   355→      return (
   356→        <>
   357→          <TacticalWideLayer
   358→            data={tacticalWideData}
   359→            fromDate={new Date(tacticalWideFromDate)}
   360→            toDate={new Date(tacticalWideToDate)}
   361→            width="100%"
   362→            height="100%"
   363→            selectedPmIds={canvasState.selection.selectedPmIds}
   364→            onBlockHover={handleTacticalWideBlockHover}
   365→            onBlockClick={handleTacticalWideBlockClick}
   366→            onMonthClick={handleMonthClick}
   367→          />
   368→          <div
   369→            ref={tooltipRef}
   370→            style={{
   371→              display: 'none',
   372→              position: 'fixed',
   373→              backgroundColor: 'white',
   374→              border: '1px solid #e2e8f0',
   375→              borderRadius: '6px',
   376→              padding: '8px 12px',
   377→              boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
   378→              pointerEvents: 'none',
   379→              zIndex: 100,
   380→              fontSize: '12px',
   381→              lineHeight: 1.5,
   382→            }}
   383→          />
   384→        </>
   385→      );
   386→    }
   387→
   388→    if (zoomLevel === 'TACTICAL') {
   389→      if (tacticalLoading) {
   390→        return (
   391→          <NonIdealState
   392→            icon={<Spinner size={48} />}
   393→            title="Loading tactical view..."
   394→            description="Fetching PM schedule data"
   395→          />
   396→        );
   397→      }
   398→
   399→      if (tacticalError) {
   400→        return (
   401→          <NonIdealState
   402→            icon="error"
   403→            title="Error loading tactical view"
   404→            description={tacticalError}
   405→            action={
   406→              <Button intent="primary" onClick={handleLoadTacticalData}>
   407→                Retry
   408→              </Button>
   409→            }
   410→          />
   411→        );
   412→      }
   413→
   414→      if (!tacticalData) {
   415→        return (
   416→          <NonIdealState
   417→            icon="gantt-chart"
   418→            title="Tactical View"
   419→            description="Load 12-week PM schedule Gantt chart"
   420→            action={
   421→              <ButtonGroup>
   422→                <Button intent="primary" onClick={handleLoadTacticalData}>
   423→                  Load Tactical Data
   424→                </Button>
   425→              </ButtonGroup>
   426→            }
   427→          >
   428→            <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
   429→              <p>Shows PM schedule from {tacticalFromDate} to {tacticalToDate}</p>
   430→            </div>
   431→          </NonIdealState>
   432→        );
   433→      }
   434→
   435→      // Build train order from tactical data
   436→      const trainIds = Array.from(new Set(tacticalData.pmBlocks.map(pm => pm.trainId)));
   437→      const containerWidth = DEFAULT_CANVAS_WIDTH;
   438→      const containerHeight = DEFAULT_CANVAS_HEIGHT;
   439→
   440→      return (
   441→        <>
   442→          <TacticalGanttLayer
   443→            data={tacticalData}
   444→            trainOrder={trainIds}
   445→            fromDate={new Date(tacticalFromDate)}
   446→            toDate={new Date(tacticalToDate)}
   447→            width={containerWidth}
   448→            height={containerHeight}
   449→            selectedPmIds={canvasState.selection.selectedPmIds}
   450→            onPmClick={handlePmBlockClick}
   451→            onPmHover={handlePmBlockHover}
   452→            showConstraintWalls={layers.complianceWindows}
   453→            showGrid={true}
   454→          />
   455→          <div
   456→            ref={tooltipRef}
   457→            style={{
   458→              display: 'none',
   459→              position: 'fixed',
   460→              backgroundColor: 'white',
   461→              border: '1px solid #e2e8f0',
   462→              borderRadius: '6px',
   463→              padding: '8px 12px',
   464→              boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
   465→              pointerEvents: 'none',
   466→              zIndex: 100,
   467→              fontSize: '12px',
   468→              lineHeight: 1.5,
   469→            }}
   470→          />
   471→        </>
   472→      );
   473→    }
   474→
   475→    return (
   476→      <div style={{ padding: '24px', textAlign: 'center' }}>
   477→        <NonIdealState
   478→          icon="id-number"
   479→          title="Operational View"
   480→          description="4-week detailed cards"
   481→        >
   482→          <Tag large intent="warning">
   483→            {zoomLevel} - Zoom: {zoom.toFixed(1)}
   484→          </Tag>
   485→          <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
   486→            <p>React DOM overlay will render:</p>
   487→            <ul style={{ textAlign: 'left', maxWidth: '300px', margin: '8px auto' }}>
   488→              <li>Detailed PM cards with full info</li>
   489→              <li>Material status indicators</li>
   490→              <li>Track assignments</li>
   491→              <li>Edit, lock, and history actions</li>
   492→            </ul>
   493→          </div>
   494→        </NonIdealState>
   495→      </div>
   496→    );
   497→  };
   498→
   499→  return (
   500→    <div
   501→      className="mms-canvas"
   502→      style={{
   503→        flex: 1,
   504→        position: 'relative',
   505→        overflow: 'hidden',
   506→        backgroundColor: 'var(--pt-app-background-color, #f5f8fa)',
   507→        cursor: isPanning ? 'grabbing' : 'grab',
   508→      }}
   509→      onWheel={handleWheel}
   510→      onMouseDown={handleMouseDown}
   511→      onMouseUp={handleMouseUp}
   512→      onMouseLeave={handleMouseUp}
   513→      onMouseMove={handleMouseMove}
   514→    >
   515→      <div
   516→        style={{
   517→          position: 'absolute',
   518→          top: 0,
   519→          left: 0,
   520→          right: 0,
   521→          bottom: 0,
   522→          transform: `translate(${-canvasState.panX}px, ${-canvasState.panY}px)`,
   523→          transition: isPanning ? 'none' : 'transform 0.1s ease-out',
   524→        }}
   525→      >
   526→        {renderContent()}
   527→      </div>
   528→
   529→      <div style={{
   530→        position: 'absolute',
   531→        top: '12px',
   532→        right: '12px',
   533→        zIndex: 10,
   534→      }}>
   535→        <Card elevation={1} style={{ padding: '8px 12px' }}>
   536→          <div style={{ fontSize: '11px', color: 'var(--pt-text-muted)', marginBottom: '4px' }}>
   537→            Zoom Level
   538→          </div>
   539→          <div style={{ fontSize: '14px', fontWeight: 600 }}>
   540→            {zoomLevel.replace('_', ' ')}
   541→          </div>
   542→          <div style={{ fontSize: '11px', fontFamily: 'monospace' }}>
   543→            {zoom.toFixed(1)} / 20
   544→          </div>
   545→        </Card>
   546→      </div>
   547→
   548→      <div style={{
   549→        position: 'absolute',
   550→        bottom: '12px',
   551→        left: '12px',
   552→        zIndex: 10,
   553→      }}>
   554→        <Card elevation={1} style={{ padding: '8px 12px' }}>
   555→          <div style={{ fontSize: '11px' }}>
   556→            <span style={{ color: 'var(--pt-text-muted)' }}>Viewport: </span>
   557→            <span style={{ fontFamily: 'monospace' }}>
   558→              {viewport.startDate} to {viewport.endDate}
   559→            </span>
   560→          </div>
   561→          <div style={{ fontSize: '11px' }}>
   562→            <span style={{ color: 'var(--pt-text-muted)' }}>Trains: </span>
   563→            <span>{viewport.trainIds.length || 'All'}</span>
   564→          </div>
   565→        </Card>
   566→      </div>
   567→
   568→      {(canvasState.layers.manhourOverlay || canvasState.layers.driftOverlay || canvasState.layers.baselineShadow) && (
   569→        <div style={{
   570→          position: 'absolute',
   571→          top: '12px',
   572→          left: '12px',
   573→          zIndex: 10,
   574→          display: 'flex',
   575→          gap: '4px',
   576→        }}>
   577→          {canvasState.layers.manhourOverlay && (
   578→            <Tag intent="primary" icon="chart">Man-hours</Tag>
   579→          )}
   580→          {canvasState.layers.driftOverlay && (
   581→            <Tag intent="warning" icon="delta">Drift</Tag>
   582→          )}
   583→          {canvasState.layers.baselineShadow && (
   584→            <Tag minimal icon="git-commit">Baseline</Tag>
   585→          )}
   586→        </div>
   587→      )}
   588→    </div>
   589→  );
   590→}
