   408→}
   409→
   410→/** Constraint wall for compliance window boundaries */
   411→export interface TacticalConstraintWall {
   412→  pmId: string;
   413→  type: 'COMPLIANCE_START' | 'COMPLIANCE_END';
   414→  date: string;
   415→}
   416→
   417→/** Tactical canvas API response */
   418→export interface TacticalCanvasData {
   419→  pmBlocks: TacticalPmBlock[];
   420→  constraintWalls: TacticalConstraintWall[];
   421→}
   422→
   423→// =============================================================================
   424→// Tactical-Wide Canvas Data Types
   425→// =============================================================================
   426→
   427→/** Train data for tactical-wide view */
   428→export interface TacticalWideTrainData {
   429→  trainId: string;
   430→  trainNumber: string;
   431→  fleetCode: string;
   432→}
   433→
   434→/** PM block for tactical-wide compressed view */
   435→export interface TacticalWidePmBlock {
   436→  pmId: string;
   437→  trainId: string;
   438→  pmCode: string;
   439→  targetDate: string;
   440→  durationDays: number;
   441→  status: string;
   442→  isLocked: boolean;
   443→  displayColor: string;
   444→}
   445→
   446→/** Tactical-Wide canvas API response */
   447→export interface TacticalWideCanvasData {
   448→  trains: TacticalWideTrainData[];
   449→  pmBlocks: TacticalWidePmBlock[];
   450→}
   451→
   452→export interface CanvasDataState {
   453→  strategicData: StrategicCanvasData | null;
   454→  strategicLoading: boolean;
   455→  strategicError: string | null;
   456→  strategicLastFetch: number | null;
   457→  fromYear: number;
   458→  toYear: number;
   459→  tacticalWideData: TacticalWideCanvasData | null;
   460→  tacticalWideLoading: boolean;
   461→  tacticalWideError: string | null;
   462→  tacticalWideLastFetch: number | null;
   463→  tacticalWideFromDate: string;
   464→  tacticalWideToDate: string;
   465→  tacticalData: TacticalCanvasData | null;
   466→  tacticalLoading: boolean;
   467→  tacticalError: string | null;
   468→  tacticalLastFetch: number | null;
   469→  tacticalFromDate: string;
   470→  tacticalToDate: string;
   471→  [key: string]: unknown;
   472→}
   473→
   474→function getDefaultTacticalDates(): { from: string; to: string } {
   475→  const today = new Date();
   476→  const fromDate = new Date(today);
   477→  fromDate.setDate(today.getDate() - today.getDay()); // Start of current week
   478→  const toDate = new Date(fromDate);
   479→  toDate.setDate(toDate.getDate() + 12 * 7); // 12 weeks ahead
   480→  return {
   481→    from: fromDate.toISOString().split('T')[0],
   482→    to: toDate.toISOString().split('T')[0],
   483→  };
   484→}
   485→
   486→function getDefaultTacticalWideDates(): { from: string; to: string } {
   487→  const today = new Date();
   488→  const fromDate = new Date(today.getFullYear(), today.getMonth(), 1); // Start of current month
   489→  const toDate = new Date(fromDate);
   490→  toDate.setMonth(toDate.getMonth() + 12); // 12 months ahead
   491→  return {
   492→    from: fromDate.toISOString().split('T')[0],
   493→    to: toDate.toISOString().split('T')[0],
   494→  };
   495→}
   496→
   497→const tacticalDates = getDefaultTacticalDates();
   498→const tacticalWideDates = getDefaultTacticalWideDates();
   499→
   500→const initialCanvasDataState: CanvasDataState = {
   501→  strategicData: null,
   502→  strategicLoading: false,
   503→  strategicError: null,
   504→  strategicLastFetch: null,
   505→  fromYear: new Date().getFullYear(),
   506→  toYear: new Date().getFullYear() + 10,
   507→  tacticalWideData: null,
   508→  tacticalWideLoading: false,
   509→  tacticalWideError: null,
   510→  tacticalWideLastFetch: null,
   511→  tacticalWideFromDate: tacticalWideDates.from,
   512→  tacticalWideToDate: tacticalWideDates.to,
   513→  tacticalData: null,
   514→  tacticalLoading: false,
   515→  tacticalError: null,
   516→  tacticalLastFetch: null,
   517→  tacticalFromDate: tacticalDates.from,
   518→  tacticalToDate: tacticalDates.to,
   519→};
   520→
   521→export const canvasDataSlice = createSlice({
   522→  id: 'canvasData',
   523→  initial: initialCanvasDataState,
   524→  cache: { policy: 'session' },
   525→  reducers: {
   526→    setStrategicLoading: (s, loading: boolean) => {
   527→      const state = s as CanvasDataState;
   528→      state.strategicLoading = loading;
   529→    },
   530→
   531→    setStrategicData: (s, data: StrategicCanvasData) => {
   532→      const state = s as CanvasDataState;
   533→      state.strategicData = data;
   534→      state.strategicLoading = false;
   535→      state.strategicError = null;
   536→      state.strategicLastFetch = Date.now();
   537→    },
   538→
   539→    setStrategicError: (s, error: string) => {
   540→      const state = s as CanvasDataState;
   541→      state.strategicError = error;
   542→      state.strategicLoading = false;
   543→    },
   544→
   545→    setYearRange: (s, payload: { fromYear: number; toYear: number }) => {
   546→      const state = s as CanvasDataState;
   547→      state.fromYear = payload.fromYear;
   548→      state.toYear = payload.toYear;
   549→    },
   550→
   551→    clearStrategicData: (s) => {
   552→      const state = s as CanvasDataState;
   553→      state.strategicData = null;
   554→      state.strategicError = null;
   555→      state.strategicLastFetch = null;
   556→    },
   557→
   558→    // Tactical-Wide data reducers
   559→    setTacticalWideLoading: (s, loading: boolean) => {
   560→      const state = s as CanvasDataState;
   561→      state.tacticalWideLoading = loading;
   562→    },
   563→
   564→    setTacticalWideData: (s, data: TacticalWideCanvasData) => {
   565→      const state = s as CanvasDataState;
   566→      state.tacticalWideData = data;
   567→      state.tacticalWideLoading = false;
   568→      state.tacticalWideError = null;
   569→      state.tacticalWideLastFetch = Date.now();
   570→    },
   571→
   572→    setTacticalWideError: (s, error: string) => {
   573→      const state = s as CanvasDataState;
   574→      state.tacticalWideError = error;
   575→      state.tacticalWideLoading = false;
   576→    },
   577→
   578→    setTacticalWideDateRange: (s, payload: { fromDate: string; toDate: string }) => {
   579→      const state = s as CanvasDataState;
   580→      state.tacticalWideFromDate = payload.fromDate;
   581→      state.tacticalWideToDate = payload.toDate;
   582→    },
   583→
   584→    clearTacticalWideData: (s) => {
   585→      const state = s as CanvasDataState;
   586→      state.tacticalWideData = null;
   587→      state.tacticalWideError = null;
   588→      state.tacticalWideLastFetch = null;
   589→    },
   590→
   591→    // Tactical data reducers
   592→    setTacticalLoading: (s, loading: boolean) => {
   593→      const state = s as CanvasDataState;
   594→      state.tacticalLoading = loading;
   595→    },
   596→
   597→    setTacticalData: (s, data: TacticalCanvasData) => {
   598→      const state = s as CanvasDataState;
   599→      state.tacticalData = data;
   600→      state.tacticalLoading = false;
   601→      state.tacticalError = null;
   602→      state.tacticalLastFetch = Date.now();
   603→    },
   604→
   605→    setTacticalError: (s, error: string) => {
   606→      const state = s as CanvasDataState;
   607→      state.tacticalError = error;
   608→      state.tacticalLoading = false;
   609→    },
   610→
   611→    setTacticalDateRange: (s, payload: { fromDate: string; toDate: string }) => {
   612→      const state = s as CanvasDataState;
   613→      state.tacticalFromDate = payload.fromDate;
   614→      state.tacticalToDate = payload.toDate;
   615→    },
   616→
   617→    clearTacticalData: (s) => {
   618→      const state = s as CanvasDataState;
   619→      state.tacticalData = null;
   620→      state.tacticalError = null;
   621→      state.tacticalLastFetch = null;
   622→    },
   623→
   624→    reset: (s) => {
   625→      const state = s as CanvasDataState;
   626→      Object.assign(state, initialCanvasDataState);
   627→    },
   628→  },
   629→});
   630→
   631→/**
   632→ * Load strategic canvas data from API
   633→ */
   634→export async function loadStrategicData(
   635→  dispatch: {
   636→    setStrategicLoading: (loading: boolean) => void;
   637→    setStrategicData: (data: StrategicCanvasData) => void;
   638→    setStrategicError: (error: string) => void;
   639→  },
   640→  options: { baseUrl?: string; fromYear?: number; toYear?: number; fleetId?: string } = {}
   641→): Promise<void> {
   642→  const {
   643→    baseUrl = '/api/v1',
   644→    fromYear = new Date().getFullYear(),
   645→    toYear = new Date().getFullYear() + 10,
   646→    fleetId,
   647→  } = options;
   648→
   649→  dispatch.setStrategicLoading(true);
   650→
   651→  const params = new URLSearchParams();
   652→  params.set('fromYear', String(fromYear));
   653→  params.set('toYear', String(toYear));
   654→  if (fleetId) {
   655→    params.set('fleetId', fleetId);
   656→  }
   657→
   658→  try {
   659→    const response = await fetch(`${baseUrl}/canvas/strategic?${params}`);
   660→
   661→    if (!response.ok) {
   662→      throw new Error(`Failed to fetch strategic data: ${response.status}`);
   663→    }
   664→
   665→    const json = (await response.json()) as { data: StrategicCanvasData };
   666→    dispatch.setStrategicData(json.data);
   667→  } catch (error) {
   668→    const message = error instanceof Error ? error.message : 'Unknown error';
   669→    dispatch.setStrategicError(message);
   670→  }
   671→}
   672→
   673→/**
   674→ * Load tactical canvas data from API
   675→ */
   676→export async function loadTacticalData(
   677→  dispatch: {
   678→    setTacticalLoading: (loading: boolean) => void;
   679→    setTacticalData: (data: TacticalCanvasData) => void;
   680→    setTacticalError: (error: string) => void;
   681→  },
   682→  options: { baseUrl?: string; fromWeek?: string; toWeek?: string; trainIds?: string[] } = {}
   683→): Promise<void> {
   684→  const {
   685→    baseUrl = '/api/v1',
   686→    fromWeek,
   687→    toWeek,
   688→    trainIds,
   689→  } = options;
   690→
   691→  dispatch.setTacticalLoading(true);
   692→
   693→  const params = new URLSearchParams();
   694→  if (fromWeek) {
   695→    params.set('fromWeek', fromWeek);
   696→  }
   697→  if (toWeek) {
   698→    params.set('toWeek', toWeek);
   699→  }
   700→  if (trainIds && trainIds.length > 0) {
   701→    params.set('trainIds', trainIds.join(','));
   702→  }
   703→
   704→  try {
   705→    const response = await fetch(`${baseUrl}/canvas/tactical?${params}`);
   706→
   707→    if (!response.ok) {
   708→      throw new Error(`Failed to fetch tactical data: ${response.status}`);
   709→    }
   710→
   711→    const json = (await response.json()) as { data: TacticalCanvasData };
   712→    dispatch.setTacticalData(json.data);
   713→  } catch (error) {
   714→    const message = error instanceof Error ? error.message : 'Unknown error';
   715→    dispatch.setTacticalError(message);
   716→  }
   717→}
   718→
   719→/**
   720→ * Load tactical-wide canvas data from API
   721→ *
   722→ * Fetches PM schedule data aggregated at monthly granularity for the
   723→ * TACTICAL_WIDE zoom level (4-8). Shows compressed PM blocks for 1-year view.
   724→ */
   725→export async function loadTacticalWideData(
   726→  dispatch: {
   727→    setTacticalWideLoading: (loading: boolean) => void;
   728→    setTacticalWideData: (data: TacticalWideCanvasData) => void;
   729→    setTacticalWideError: (error: string) => void;
   730→  },
   731→  options: { baseUrl?: string; fromDate?: string; toDate?: string; trainIds?: string[] } = {}
   732→): Promise<void> {
   733→  const {
   734→    baseUrl = '/api/v1',
   735→    fromDate,
   736→    toDate,
   737→    trainIds,
   738→  } = options;
   739→
   740→  dispatch.setTacticalWideLoading(true);
   741→
   742→  const params = new URLSearchParams();
   743→  if (fromDate) {
   744→    params.set('fromDate', fromDate);
   745→  }
   746→  if (toDate) {
   747→    params.set('toDate', toDate);
   748→  }
   749→  if (trainIds && trainIds.length > 0) {
   750→    params.set('trainIds', trainIds.join(','));
   751→  }
   752→
   753→  try {
   754→    // Tactical-wide uses the tactical endpoint with monthly aggregation
   755→    // The API returns the same data format but filtered for the date range
   756→    const response = await fetch(`${baseUrl}/canvas/tactical-wide?${params}`);
   757→
   758→    if (!response.ok) {
   759→      throw new Error(`Failed to fetch tactical-wide data: ${response.status}`);
   760→    }
   761→
   762→    const json = (await response.json()) as { data: TacticalWideCanvasData };
   763→    dispatch.setTacticalWideData(json.data);
   764→  } catch (error) {
   765→    const message = error instanceof Error ? error.message : 'Unknown error';
   766→    dispatch.setTacticalWideError(message);
   767→  }
   768→}
