/**
 * Canvas Slice
 *
 * State management for the infinite canvas: viewport, zoom, pan, layers.
 * Optimized for 60fps WebGL rendering with deck.gl.
 *
 * @see specs/006-user-interface.md Section 6.3
 */

import { createSlice } from '@belt/tools';
import type { ZoomLevel, ViewportBounds, LayerVisibility, CanvasSelection } from '../types';

// =============================================================================
// Constants
// =============================================================================

export const ZOOM_THRESHOLDS = {
  STRATEGIC: { min: 0, max: 4, granularity: 'year' as const },
  TACTICAL_WIDE: { min: 4, max: 8, granularity: 'month' as const },
  TACTICAL: { min: 8, max: 12, granularity: 'week' as const },
  OPERATIONAL: { min: 12, max: 16, granularity: 'day' as const },
  DETAIL: { min: 16, max: 20, granularity: 'hour' as const },
};

export function getZoomLevelName(zoom: number): ZoomLevel {
  if (zoom < ZOOM_THRESHOLDS.TACTICAL_WIDE.min) return 'STRATEGIC';
  if (zoom < ZOOM_THRESHOLDS.TACTICAL.min) return 'TACTICAL_WIDE';
  if (zoom < ZOOM_THRESHOLDS.OPERATIONAL.min) return 'TACTICAL';
  if (zoom < ZOOM_THRESHOLDS.DETAIL.min) return 'OPERATIONAL';
  return 'DETAIL';
}

// =============================================================================
// Canvas Slice State
// =============================================================================

interface AnimationTarget {
  zoom: number | null;
  panX: number | null;
  panY: number | null;
}

export interface CanvasSliceState {
  zoom: number;
  panX: number;
  panY: number;
  zoomLevel: ZoomLevel;
  viewport: ViewportBounds;
  layers: LayerVisibility;
  selection: CanvasSelection;
  todayDate: string;
  isViewportLocked: boolean;
  showMinimap: boolean;
  showGrid: boolean;
  isPerformanceMode: boolean;
  isPanning: boolean;
  isZooming: boolean;
  animationTarget: AnimationTarget;
  [key: string]: unknown;
}

const initialCanvasState: CanvasSliceState = {
  zoom: 10,
  panX: 0,
  panY: 0,
  zoomLevel: 'TACTICAL',
  viewport: {
    startDate: new Date().toISOString().split('T')[0],
    endDate: new Date(Date.now() + 84 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    trainIds: [],
  },
  layers: {
    pmBlocks: true,
    complianceWindows: true,
    manhourOverlay: false,
    driftOverlay: false,
    baselineShadow: false,
  },
  selection: {
    selectedPmIds: [],
    selectedTrainIds: [],
    isMultiSelect: false,
  },
  todayDate: new Date().toISOString().split('T')[0],
  isViewportLocked: false,
  showMinimap: true,
  showGrid: true,
  isPerformanceMode: false,
  isPanning: false,
  isZooming: false,
  animationTarget: {
    zoom: null,
    panX: null,
    panY: null,
  },
};

export const canvasSlice = createSlice({
  id: 'canvas',
  initial: initialCanvasState,
  cache: { policy: 'session' },
  reducers: {
    // Viewport Control
    setZoom: (s, zoom: number) => {
      const state = s as CanvasSliceState;
      const clampedZoom = Math.max(0, Math.min(20, zoom));
      state.zoom = clampedZoom;
      state.zoomLevel = getZoomLevelName(clampedZoom);
    },

    zoomIn: (s, factor = 1.2) => {
      const state = s as CanvasSliceState;
      const newZoom = Math.min(20, state.zoom * factor);
      state.zoom = newZoom;
      state.zoomLevel = getZoomLevelName(newZoom);
    },

    zoomOut: (s, factor = 1.2) => {
      const state = s as CanvasSliceState;
      const newZoom = Math.max(0, state.zoom / factor);
      state.zoom = newZoom;
      state.zoomLevel = getZoomLevelName(newZoom);
    },

    setZoomLevel: (s, level: ZoomLevel) => {
      const state = s as CanvasSliceState;
      const thresholds = ZOOM_THRESHOLDS[level];
      const targetZoom = (thresholds.min + thresholds.max) / 2;
      state.zoom = targetZoom;
      state.zoomLevel = level;
    },

    setPan: (s, payload: { x: number; y: number }) => {
      const state = s as CanvasSliceState;
      state.panX = payload.x;
      state.panY = payload.y;
    },

    pan: (s, delta: { dx: number; dy: number }) => {
      const state = s as CanvasSliceState;
      state.panX += delta.dx;
      state.panY += delta.dy;
    },

    setViewport: (s, viewport: Partial<ViewportBounds>) => {
      const state = s as CanvasSliceState;
      state.viewport = { ...state.viewport, ...viewport };
    },

    // Layer Control
    setLayerVisibility: (s, layers: Partial<LayerVisibility>) => {
      const state = s as CanvasSliceState;
      state.layers = { ...state.layers, ...layers };
    },

    toggleLayer: (s, layer: keyof LayerVisibility) => {
      const state = s as CanvasSliceState;
      state.layers[layer] = !state.layers[layer];
    },

    showAllLayers: (s) => {
      const state = s as CanvasSliceState;
      state.layers = {
        pmBlocks: true,
        complianceWindows: true,
        manhourOverlay: true,
        driftOverlay: true,
        baselineShadow: true,
      };
    },

    hideAllOverlays: (s) => {
      const state = s as CanvasSliceState;
      state.layers.manhourOverlay = false;
      state.layers.driftOverlay = false;
      state.layers.baselineShadow = false;
    },

    // Selection
    selectPm: (s, pmId: string) => {
      const state = s as CanvasSliceState;
      if (state.selection.isMultiSelect) {
        if (!state.selection.selectedPmIds.includes(pmId)) {
          state.selection.selectedPmIds.push(pmId);
        }
      } else {
        state.selection.selectedPmIds = [pmId];
      }
    },

    deselectPm: (s, pmId: string) => {
      const state = s as CanvasSliceState;
      state.selection.selectedPmIds = state.selection.selectedPmIds.filter((id) => id !== pmId);
    },

    selectTrain: (s, trainId: string) => {
      const state = s as CanvasSliceState;
      if (state.selection.isMultiSelect) {
        if (!state.selection.selectedTrainIds.includes(trainId)) {
          state.selection.selectedTrainIds.push(trainId);
        }
      } else {
        state.selection.selectedTrainIds = [trainId];
      }
    },

    deselectTrain: (s, trainId: string) => {
      const state = s as CanvasSliceState;
      state.selection.selectedTrainIds = state.selection.selectedTrainIds.filter(
        (id) => id !== trainId
      );
    },

    setMultiSelect: (s, enabled: boolean) => {
      const state = s as CanvasSliceState;
      state.selection.isMultiSelect = enabled;
    },

    clearSelection: (s) => {
      const state = s as CanvasSliceState;
      state.selection.selectedPmIds = [];
      state.selection.selectedTrainIds = [];
    },

    selectAll: (s, payload: { pmIds?: string[]; trainIds?: string[] }) => {
      const state = s as CanvasSliceState;
      if (payload.pmIds) {
        state.selection.selectedPmIds = payload.pmIds;
      }
      if (payload.trainIds) {
        state.selection.selectedTrainIds = payload.trainIds;
      }
    },

    // Navigation
    goToToday: (s) => {
      const state = s as CanvasSliceState;
      state.todayDate = new Date().toISOString().split('T')[0];
      state.panX = 0;
    },

    goToDate: (s, date: string) => {
      const state = s as CanvasSliceState;
      state.viewport.startDate = date;
    },

    // UI Controls
    toggleMinimap: (s) => {
      const state = s as CanvasSliceState;
      state.showMinimap = !state.showMinimap;
    },

    toggleGrid: (s) => {
      const state = s as CanvasSliceState;
      state.showGrid = !state.showGrid;
    },

    setPerformanceMode: (s, enabled: boolean) => {
      const state = s as CanvasSliceState;
      state.isPerformanceMode = enabled;
    },

    lockViewport: (s) => {
      const state = s as CanvasSliceState;
      state.isViewportLocked = true;
    },

    unlockViewport: (s) => {
      const state = s as CanvasSliceState;
      state.isViewportLocked = false;
    },

    // Interaction State
    startPanning: (s) => {
      const state = s as CanvasSliceState;
      state.isPanning = true;
    },

    stopPanning: (s) => {
      const state = s as CanvasSliceState;
      state.isPanning = false;
    },

    startZooming: (s) => {
      const state = s as CanvasSliceState;
      state.isZooming = true;
    },

    stopZooming: (s) => {
      const state = s as CanvasSliceState;
      state.isZooming = false;
    },

    // Animation
    setAnimationTarget: (
      s,
      target: { zoom?: number | null; panX?: number | null; panY?: number | null }
    ) => {
      const state = s as CanvasSliceState;
      state.animationTarget = {
        zoom: target.zoom ?? state.animationTarget.zoom,
        panX: target.panX ?? state.animationTarget.panX,
        panY: target.panY ?? state.animationTarget.panY,
      };
    },

    clearAnimationTarget: (s) => {
      const state = s as CanvasSliceState;
      state.animationTarget = { zoom: null, panX: null, panY: null };
    },

    // Reset
    reset: (s) => {
      const state = s as CanvasSliceState;
      Object.assign(state, initialCanvasState);
    },

    resetViewport: (s) => {
      const state = s as CanvasSliceState;
      state.zoom = 10;
      state.panX = 0;
      state.panY = 0;
      state.zoomLevel = 'TACTICAL';
    },
  },
});

// =============================================================================
// Selectors
// =============================================================================

export function isPmSelected(state: CanvasSliceState, pmId: string): boolean {
  return state.selection.selectedPmIds.includes(pmId);
}

export function isTrainSelected(state: CanvasSliceState, trainId: string): boolean {
  return state.selection.selectedTrainIds.includes(trainId);
}

export function getGranularity(
  state: CanvasSliceState
): 'year' | 'month' | 'week' | 'day' | 'hour' {
  return ZOOM_THRESHOLDS[state.zoomLevel].granularity;
}

export function viewportContainsDate(state: CanvasSliceState, date: string): boolean {
  return date >= state.viewport.startDate && date <= state.viewport.endDate;
}

export function getVisibleTrainIds(state: CanvasSliceState): string[] {
  return state.viewport.trainIds;
}

export function hasActiveOverlay(state: CanvasSliceState): boolean {
  return state.layers.manhourOverlay || state.layers.driftOverlay || state.layers.baselineShadow;
}

// =============================================================================
// Canvas Data Types
// =============================================================================

/** Strategic year data from API */
export interface StrategicYearData {
  year: number;
  pmCount: number;
  totalHours: number;
  completedCount: number;
  lockedCount: number;
}

/** Strategic train data from API */
export interface StrategicTrainData {
  trainId: string;
  trainNumber: string;
  fleetCode: string;
  years: StrategicYearData[];
}

/** Strategic canvas API response */
export interface StrategicCanvasData {
  trains: StrategicTrainData[];
  heatmapData: {
    maxPmCount: number;
    maxHours: number;
  };
}

// =============================================================================
// Canvas Data Slice
// =============================================================================

/** Tactical PM block data from API */
export interface TacticalPmBlock {
  pmId: string;
  trainId: string;
  trainNumber: string;
  pmCode: string;
  targetDate: string;
  durationDays: number;
  status: string;
  constraintStart: string;
  constraintEnd: string;
  isLocked: boolean;
  trackNumber: string | null;
  depotCode: string | null;
  displayColor: string;
  estimatedHours: number | null;
}

/** Constraint wall for compliance window boundaries */
export interface TacticalConstraintWall {
  pmId: string;
  type: 'COMPLIANCE_START' | 'COMPLIANCE_END';
  date: string;
}

/** Tactical canvas API response */
export interface TacticalCanvasData {
  pmBlocks: TacticalPmBlock[];
  constraintWalls: TacticalConstraintWall[];
}

// =============================================================================
// Tactical-Wide Canvas Data Types
// =============================================================================

/** Train data for tactical-wide view */
export interface TacticalWideTrainData {
  trainId: string;
  trainNumber: string;
  fleetCode: string;
}

/** PM block for tactical-wide compressed view */
export interface TacticalWidePmBlock {
  pmId: string;
  trainId: string;
  pmCode: string;
  targetDate: string;
  durationDays: number;
  status: string;
  isLocked: boolean;
  displayColor: string;
}

/** Tactical-Wide canvas API response */
export interface TacticalWideCanvasData {
  trains: TacticalWideTrainData[];
  pmBlocks: TacticalWidePmBlock[];
}

export interface CanvasDataState {
  strategicData: StrategicCanvasData | null;
  strategicLoading: boolean;
  strategicError: string | null;
  strategicLastFetch: number | null;
  fromYear: number;
  toYear: number;
  tacticalWideData: TacticalWideCanvasData | null;
  tacticalWideLoading: boolean;
  tacticalWideError: string | null;
  tacticalWideLastFetch: number | null;
  tacticalWideFromDate: string;
  tacticalWideToDate: string;
  tacticalData: TacticalCanvasData | null;
  tacticalLoading: boolean;
  tacticalError: string | null;
  tacticalLastFetch: number | null;
  tacticalFromDate: string;
  tacticalToDate: string;
  [key: string]: unknown;
}

function getDefaultTacticalDates(): { from: string; to: string } {
  const today = new Date();
  const fromDate = new Date(today);
  fromDate.setDate(today.getDate() - today.getDay()); // Start of current week
  const toDate = new Date(fromDate);
  toDate.setDate(toDate.getDate() + 12 * 7); // 12 weeks ahead
  return {
    from: fromDate.toISOString().split('T')[0],
    to: toDate.toISOString().split('T')[0],
  };
}

function getDefaultTacticalWideDates(): { from: string; to: string } {
  const today = new Date();
  const fromDate = new Date(today.getFullYear(), today.getMonth(), 1); // Start of current month
  const toDate = new Date(fromDate);
  toDate.setMonth(toDate.getMonth() + 12); // 12 months ahead
  return {
    from: fromDate.toISOString().split('T')[0],
    to: toDate.toISOString().split('T')[0],
  };
}

const tacticalDates = getDefaultTacticalDates();
const tacticalWideDates = getDefaultTacticalWideDates();

const initialCanvasDataState: CanvasDataState = {
  strategicData: null,
  strategicLoading: false,
  strategicError: null,
  strategicLastFetch: null,
  fromYear: new Date().getFullYear(),
  toYear: new Date().getFullYear() + 10,
  tacticalWideData: null,
  tacticalWideLoading: false,
  tacticalWideError: null,
  tacticalWideLastFetch: null,
  tacticalWideFromDate: tacticalWideDates.from,
  tacticalWideToDate: tacticalWideDates.to,
  tacticalData: null,
  tacticalLoading: false,
  tacticalError: null,
  tacticalLastFetch: null,
  tacticalFromDate: tacticalDates.from,
  tacticalToDate: tacticalDates.to,
};

export const canvasDataSlice = createSlice({
  id: 'canvasData',
  initial: initialCanvasDataState,
  cache: { policy: 'session' },
  reducers: {
    setStrategicLoading: (s, loading: boolean) => {
      const state = s as CanvasDataState;
      state.strategicLoading = loading;
    },

    setStrategicData: (s, data: StrategicCanvasData) => {
      const state = s as CanvasDataState;
      state.strategicData = data;
      state.strategicLoading = false;
      state.strategicError = null;
      state.strategicLastFetch = Date.now();
    },

    setStrategicError: (s, error: string) => {
      const state = s as CanvasDataState;
      state.strategicError = error;
      state.strategicLoading = false;
    },

    setYearRange: (s, payload: { fromYear: number; toYear: number }) => {
      const state = s as CanvasDataState;
      state.fromYear = payload.fromYear;
      state.toYear = payload.toYear;
    },

    clearStrategicData: (s) => {
      const state = s as CanvasDataState;
      state.strategicData = null;
      state.strategicError = null;
      state.strategicLastFetch = null;
    },

    // Tactical-Wide data reducers
    setTacticalWideLoading: (s, loading: boolean) => {
      const state = s as CanvasDataState;
      state.tacticalWideLoading = loading;
    },

    setTacticalWideData: (s, data: TacticalWideCanvasData) => {
      const state = s as CanvasDataState;
      state.tacticalWideData = data;
      state.tacticalWideLoading = false;
      state.tacticalWideError = null;
      state.tacticalWideLastFetch = Date.now();
    },

    setTacticalWideError: (s, error: string) => {
      const state = s as CanvasDataState;
      state.tacticalWideError = error;
      state.tacticalWideLoading = false;
    },

    setTacticalWideDateRange: (s, payload: { fromDate: string; toDate: string }) => {
      const state = s as CanvasDataState;
      state.tacticalWideFromDate = payload.fromDate;
      state.tacticalWideToDate = payload.toDate;
    },

    clearTacticalWideData: (s) => {
      const state = s as CanvasDataState;
      state.tacticalWideData = null;
      state.tacticalWideError = null;
      state.tacticalWideLastFetch = null;
    },

    // Tactical data reducers
    setTacticalLoading: (s, loading: boolean) => {
      const state = s as CanvasDataState;
      state.tacticalLoading = loading;
    },

    setTacticalData: (s, data: TacticalCanvasData) => {
      const state = s as CanvasDataState;
      state.tacticalData = data;
      state.tacticalLoading = false;
      state.tacticalError = null;
      state.tacticalLastFetch = Date.now();
    },

    setTacticalError: (s, error: string) => {
      const state = s as CanvasDataState;
      state.tacticalError = error;
      state.tacticalLoading = false;
    },

    setTacticalDateRange: (s, payload: { fromDate: string; toDate: string }) => {
      const state = s as CanvasDataState;
      state.tacticalFromDate = payload.fromDate;
      state.tacticalToDate = payload.toDate;
    },

    clearTacticalData: (s) => {
      const state = s as CanvasDataState;
      state.tacticalData = null;
      state.tacticalError = null;
      state.tacticalLastFetch = null;
    },

    reset: (s) => {
      const state = s as CanvasDataState;
      Object.assign(state, initialCanvasDataState);
    },
  },
});

/**
 * Load strategic canvas data from API
 */
export async function loadStrategicData(
  dispatch: {
    setStrategicLoading: (loading: boolean) => void;
    setStrategicData: (data: StrategicCanvasData) => void;
    setStrategicError: (error: string) => void;
  },
  options: { baseUrl?: string; fromYear?: number; toYear?: number; fleetId?: string } = {}
): Promise<void> {
  const {
    baseUrl = '/api/v1',
    fromYear = new Date().getFullYear(),
    toYear = new Date().getFullYear() + 10,
    fleetId,
  } = options;

  dispatch.setStrategicLoading(true);

  const params = new URLSearchParams();
  params.set('fromYear', String(fromYear));
  params.set('toYear', String(toYear));
  if (fleetId) {
    params.set('fleetId', fleetId);
  }

  try {
    const response = await fetch(`${baseUrl}/canvas/strategic?${params}`);

    if (!response.ok) {
      throw new Error(`Failed to fetch strategic data: ${response.status}`);
    }

    const json = (await response.json()) as { data: StrategicCanvasData };
    dispatch.setStrategicData(json.data);
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    dispatch.setStrategicError(message);
  }
}

/**
 * Load tactical canvas data from API
 */
export async function loadTacticalData(
  dispatch: {
    setTacticalLoading: (loading: boolean) => void;
    setTacticalData: (data: TacticalCanvasData) => void;
    setTacticalError: (error: string) => void;
  },
  options: { baseUrl?: string; fromWeek?: string; toWeek?: string; trainIds?: string[] } = {}
): Promise<void> {
  const {
    baseUrl = '/api/v1',
    fromWeek,
    toWeek,
    trainIds,
  } = options;

  dispatch.setTacticalLoading(true);

  const params = new URLSearchParams();
  if (fromWeek) {
    params.set('fromWeek', fromWeek);
  }
  if (toWeek) {
    params.set('toWeek', toWeek);
  }
  if (trainIds && trainIds.length > 0) {
    params.set('trainIds', trainIds.join(','));
  }

  try {
    const response = await fetch(`${baseUrl}/canvas/tactical?${params}`);

    if (!response.ok) {
      throw new Error(`Failed to fetch tactical data: ${response.status}`);
    }

    const json = (await response.json()) as { data: TacticalCanvasData };
    dispatch.setTacticalData(json.data);
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    dispatch.setTacticalError(message);
  }
}

/**
 * Load tactical-wide canvas data from API
 *
 * Fetches PM schedule data aggregated at monthly granularity for the
 * TACTICAL_WIDE zoom level (4-8). Shows compressed PM blocks for 1-year view.
 */
export async function loadTacticalWideData(
  dispatch: {
    setTacticalWideLoading: (loading: boolean) => void;
    setTacticalWideData: (data: TacticalWideCanvasData) => void;
    setTacticalWideError: (error: string) => void;
  },
  options: { baseUrl?: string; fromDate?: string; toDate?: string; trainIds?: string[] } = {}
): Promise<void> {
  const {
    baseUrl = '/api/v1',
    fromDate,
    toDate,
    trainIds,
  } = options;

  dispatch.setTacticalWideLoading(true);

  const params = new URLSearchParams();
  if (fromDate) {
    params.set('fromDate', fromDate);
  }
  if (toDate) {
    params.set('toDate', toDate);
  }
  if (trainIds && trainIds.length > 0) {
    params.set('trainIds', trainIds.join(','));
  }

  try {
    // Tactical-wide uses the tactical endpoint with monthly aggregation
    // The API returns the same data format but filtered for the date range
    const response = await fetch(`${baseUrl}/canvas/tactical-wide?${params}`);

    if (!response.ok) {
      throw new Error(`Failed to fetch tactical-wide data: ${response.status}`);
    }

    const json = (await response.json()) as { data: TacticalWideCanvasData };
    dispatch.setTacticalWideData(json.data);
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    dispatch.setTacticalWideError(message);
  }
}

/**
 * MMS Color System
 *
 * Defines the color palette for the MMS application.
 * Based on specs/006-user-interface.md Section 6.1.3.
 */

/** PM Status Colors */
export const PM_STATUS_COLORS = {
  scheduled: '#3B82F6',    // Blue
  inProgress: '#F59E0B',   // Amber
  completed: '#10B981',    // Green
  cancelled: '#6B7280',    // Gray
  deferred: '#8B5CF6',     // Purple
  overdue: '#EF4444',      // Red
} as const;

/** Constraint Indicator Colors */
export const CONSTRAINT_COLORS = {
  hardViolation: '#DC2626',    // Red-600
  softViolation: '#F59E0B',    // Amber-500
  approaching: '#FBBF24',      // Yellow-400
  ok: '#10B981',               // Green-500
} as const;

/** Drift Severity Colors */
export const DRIFT_COLORS = {
  critical: '#DC2626',     // Red
  warning: '#F59E0B',      // Amber
  ok: '#10B981',           // Green
} as const;

/** Man-hour Utilization Colors */
export const UTILIZATION_COLORS = {
  overloaded: '#DC2626',   // Red
  optimal: '#10B981',      // Green
  underutilized: '#3B82F6', // Blue
} as const;

/** Fleet Colors */
export const FLEET_COLORS = {
  KS: '#0EA5E9',           // Sky-500
  ALSTOM: '#8B5CF6',       // Violet-500
} as const;

/** Fitness Status Colors */
export const FITNESS_STATUS_COLORS = {
  FIT: '#10B981',          // Green
  RESTRICTED: '#F59E0B',   // Amber
  GROUNDED: '#EF4444',     // Red
} as const;

/** Zoom Level Thresholds */
export const ZOOM_THRESHOLDS = {
  STRATEGIC: { min: 0, max: 4 },
  TACTICAL_WIDE: { min: 4, max: 8 },
  TACTICAL: { min: 8, max: 12 },
  OPERATIONAL: { min: 12, max: 16 },
  DETAIL: { min: 16, max: 20 },
} as const;

export type PmStatusColor = keyof typeof PM_STATUS_COLORS;
export type ConstraintColor = keyof typeof CONSTRAINT_COLORS;
export type DriftColor = keyof typeof DRIFT_COLORS;
export type UtilizationColor = keyof typeof UTILIZATION_COLORS;
export type FleetColor = keyof typeof FLEET_COLORS;
export type FitnessColor = keyof typeof FITNESS_STATUS_COLORS;

